// Recibir datos del workflow principal o de reintento
const body = $input.first().json.body || $input.first().json;

const guiaCodigo = body.guia_codigo || '';
const tourCode = body.tour_code || '';
const fecha = body.fecha || '';
const hora = body.hora || '';
const personas = body.personas || 0;
const productId = body.product_id || '';
const calendarEventId = body.calendar_event_id || '';
const timeoutHoras = body.timeout_horas || 24;

// Generar ID único para esta confirmación
const confirmId = `CONF-${Date.now()}-${Math.random().toString(36).substring(2, 7)}`;

// URL base del webhook de respuesta (AJUSTAR con tu dominio n8n)
const baseUrl = 'REPLACE_CON_TU_N8N_URL/webhook/respuesta-guia';
const urlConfirmar = `${baseUrl}?action=confirm&id=${confirmId}`;
const urlRechazar = `${baseUrl}?action=reject&id=${confirmId}`;

return [{
  json: {
    confirmId,
    guiaCodigo,
    tourCode,
    fecha,
    hora,
    personas,
    productId,
    calendarEventId,
    timeoutHoras,
    urlConfirmar,
    urlRechazar,
    timestamp: DateTime.now().setZone('Europe/Madrid').toISO()
  }
}];

// Combinar datos de la solicitud + datos del guía
const guiaData = $input.first().json;
const solicitud = $node["Preparar Solicitud"].json;

const nombre = guiaData.nombre || solicitud.guiaCodigo;
const email = guiaData.email || '';
const telefono = guiaData.telefono_whatsapp || '';
const tieneWhatsApp = telefono && telefono.length > 5;

// Mensaje para el guía
const mensajeTexto = `Hola ${nombre} 👋

Te necesitamos para un tour:
🎯 ${solicitud.tourCode} — ${solicitud.fecha} a las ${solicitud.hora}
👥 ${solicitud.personas} personas

¿Estás disponible?

✅ CONFIRMAR:\n${solicitud.urlConfirmar}

❌ NO DISPONIBLE:\n${solicitud.urlRechazar}

⏰ Tienes ${solicitud.timeoutHoras}h para responder.

— Gourmet Madrid`;

const mensajeHtml = `<div style="font-family:Arial,sans-serif;max-width:500px">
<h3>Hola ${nombre} 👋</h3>
<p>Te necesitamos para un tour:</p>
<table style="border-collapse:collapse;width:100%;margin:12px 0">
<tr><td style="padding:8px;background:#f8f9fa;border:1px solid #dee2e6;font-weight:bold">Tour</td><td style="padding:8px;border:1px solid #dee2e6">${solicitud.tourCode}</td></tr>
<tr><td style="padding:8px;background:#f8f9fa;border:1px solid #dee2e6;font-weight:bold">Fecha</td><td style="padding:8px;border:1px solid #dee2e6">${solicitud.fecha} a las ${solicitud.hora}</td></tr>
<tr><td style="padding:8px;background:#f8f9fa;border:1px solid #dee2e6;font-weight:bold">Personas</td><td style="padding:8px;border:1px solid #dee2e6">${solicitud.personas}</td></tr>
</table>
<p>¿Estás disponible?</p>
<div style="margin:20px 0">
<a href="${solicitud.urlConfirmar}" style="display:inline-block;background:#27ae60;color:white;padding:12px 24px;text-decoration:none;border-radius:6px;margin-right:12px;font-weight:bold">✅ CONFIRMAR</a>
<a href="${solicitud.urlRechazar}" style="display:inline-block;background:#e74c3c;color:white;padding:12px 24px;text-decoration:none;border-radius:6px;font-weight:bold">❌ NO DISPONIBLE</a>
</div>
<p style="color:#888;font-size:12px">⏰ Tienes ${solicitud.timeoutHoras}h para responder.</p>
</div>`;

return [{
  json: {
    ...solicitud,
    nombre,
    email,
    telefono,
    tieneWhatsApp,
    mensajeTexto,
    mensajeHtml
  }
}];
